@namespace Lumeo
@implements IAsyncDisposable
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@* The wrapper is the labelled region; Escape/Delete clears when focus is
   inside it so keyboard / switch-access users aren't forced to mouse the clear
   button. tabindex makes the region focusable for that handler. *@
<div id="@_wrapperId"
     class="@WrapperClass"
     role="group"
     aria-label="@L["SignaturePad.Label"]"
     tabindex="0"
     @onkeydown="HandleKeyDownAsync"
     @attributes="AdditionalAttributes">
    <canvas id="@_canvasId"
            width="@Width"
            height="@Height"
            class="@CanvasClass"
            aria-hidden="true"
            style="background: @BackgroundColor;"></canvas>

    @if (string.IsNullOrEmpty(_currentValue))
    {
        <span class="absolute inset-0 flex items-center justify-center text-muted-foreground/60 text-sm pointer-events-none italic select-none">
            @Placeholder
        </span>
    }

    @if (!Disabled && (ShowClearButton || ShowDownloadButton))
    {
        <Flex Gap="2" Class="absolute end-2 top-2">
            @if (ShowDownloadButton)
            {
                <Button Variant="Button.ButtonVariant.Ghost"
                        Size="Button.ButtonSize.Icon"
                        OnClick="HandleDownloadAsync"
                        aria-label="@L["SignaturePad.Download"]">
                    <SvgGlyph Svg="@(LumeoIcons.Download)" class="h-4 w-4" />
                </Button>
            }
            @if (ShowClearButton)
            {
                <Button Variant="Button.ButtonVariant.Ghost"
                        Size="Button.ButtonSize.Icon"
                        OnClick="ClearAsync"
                        Disabled="@string.IsNullOrEmpty(_currentValue)"
                        aria-label="@L["SignaturePad.Clear"]">
                    <SvgGlyph Svg="@(LumeoIcons.Eraser)" class="h-4 w-4" />
                </Button>
            }
        </Flex>
    }

    @* Polite live region so a screen reader hears when the pad is cleared —
       the visual change (blank canvas) is otherwise silent. *@
    <span aria-live="polite" class="sr-only">@_statusMessage</span>
</div>

@inject IComponentInteropService Interop

@code {
    [Parameter] public string? Value { get; set; }
    [Parameter] public EventCallback<string?> ValueChanged { get; set; }

    [Parameter] public int Width { get; set; } = 500;
    [Parameter] public int Height { get; set; } = 200;

    [Parameter] public string StrokeColor { get; set; } = "currentColor";
    [Parameter] public double StrokeWidth { get; set; } = 2.0;
    [Parameter] public string BackgroundColor { get; set; } = "transparent";

    [Parameter] public bool ShowClearButton { get; set; } = true;
    [Parameter] public bool ShowDownloadButton { get; set; }

    /// <summary>
    /// Export format for the emitted data URL. <c>"png"</c> is the default
    /// (universal browser support, transparent backgrounds). <c>"svg"</c>
    /// produces a real vector export: the JS pad records each pointer path and
    /// replays it as <c>&lt;path&gt;</c> elements, so the signature scales
    /// crisply at any size. (A signature loaded from an existing raster data
    /// URL has no vector data to export and falls back to PNG.)
    /// </summary>
    [Parameter] public string Format { get; set; } = "png";

    [Parameter] public bool Disabled { get; set; }

    [Parameter] public EventCallback OnSign { get; set; }
    [Parameter] public EventCallback OnClear { get; set; }

    [Parameter] public string? Placeholder { get; set; } = "Sign here";

    private string? _statusMessage;

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _canvasId = LumeoIds.New("signature-pad");
    // The labelled wrapper region. Clearing via the Clear button disables that
    // button (it's empty now), so the browser drops keyboard focus to <body>.
    // We give the wrapper a stable id so ClearAsync can restore focus to the
    // region after clearing, keeping the pad keyboard-operable.
    private readonly string _wrapperId = LumeoIds.New("signature-pad-region");
    private DotNetObjectReference<SignaturePad>? _selfRef;
    private bool _initialised;

    // The live, displayed value. Seeded from the Value parameter, then mutated
    // by our own JS-emitted strokes (OnStrokeEnded) and ClearAsync. The markup
    // (placeholder, Clear-button disabled state, download fallback) reads THIS,
    // not the raw [Parameter], so a one-way / normalised parent re-render can't
    // wipe the just-drawn signature — Value stays a true controlled parameter.
    private string? _currentValue;
    // The last value the PARENT actually supplied via the Value parameter,
    // captured on every OnParametersSet. A one-way binding re-supplies the SAME
    // value every render (commonly null), so comparing the incoming Value
    // against this detects a real consumer-driven change vs. an unchanged echo.
    private string? _lastParamValue;
    // The last value WE pushed to the parent via ValueChanged (seeded to Value at
    // init). A *controlled* parent echoes this exact string back as Value; we
    // recognise that echo and skip the destructive raster reload so vector stroke
    // data is preserved. Any OTHER incoming Value — normalisation, programmatic
    // reset, or a REJECTION where the parent kept the old value — is authoritative
    // and must repaint the canvas back to the bound Value (Codex P2 fix).
    private string? _lastPushed;
    private bool _paramSeeded;
    // Set true in OnParametersSet when the parent genuinely changed Value,
    // consumed in OnAfterRenderAsync to repaint the canvas from the new value.
    private bool _pendingParamReload;

    private string? _lastStrokeColor;
    private double _lastStrokeWidth;
    private bool _lastDisabled;
    // The canvas surface dimensions last applied to the DOM. Changing the
    // <canvas> width/height attribute resets (blanks) its drawing buffer, so a
    // runtime Width/Height change wipes the rendered signature. We track the
    // applied values and repaint the existing signature after the surface reset.
    private int _lastWidth;
    private int _lastHeight;

    private string MimeType => Format?.Equals("svg", StringComparison.OrdinalIgnoreCase) == true
        ? "image/svg+xml"
        : "image/png";

    private string WrapperClass =>
        Cx.Merge("relative inline-block rounded-lg border border-border/40 bg-card", Class);

    private string CanvasClass =>
        $"touch-none rounded-lg block {(Disabled ? "pointer-events-none opacity-60" : "cursor-crosshair")}".Trim();

    protected override void OnParametersSet()
    {
        // Seed the working value from the parameter on first set; seed both
        // discriminators so neither fires on the very first normal render.
        if (!_paramSeeded)
        {
            _currentValue = Value;
            _lastParamValue = Value;
            _lastPushed = Value;
            _paramSeeded = true;
            return;
        }

        if (ValueChanged.HasDelegate)
        {
            // CONTROLLED: parent owns Value. Echo of our own push (Value ==
            // _lastPushed) → canvas already shows it, skip destructive reload so
            // vector stroke data is preserved. Any other Value — normalisation,
            // programmatic reset, or a REJECTION where the parent kept the OLD
            // value (!= what we emitted) — is authoritative and must repaint the
            // canvas back to the bound Value (Codex P2 fix).
            //
            // NOTE (Codex P2, later round): a callback-only observer that never
            // binds Value back also hits this "rejection" path when its unbound
            // default (null) is unchanged, clearing the just-drawn signature.
            // Deliberately NOT adding a null-only observer carve-out here (unlike
            // Input/ToggleGroup): SignaturePadValuePersistenceTests.
            // Controlled_Parent_Rejection_Repaints_Canvas_To_Bound_Value already
            // covers this EXACT null-baseline shape (bound stays null throughout,
            // callback never updates it) and deliberately asserts the OPPOSITE —
            // that a rejection must erase the canvas back to empty. The two
            // scenarios are 100% indistinguishable from OnParametersSet's
            // perspective (both start null and stay null forever), so satisfying
            // the new ask would silently regress that established, already-tested
            // contract. Revisit only if a signal distinguishing them is found.
            if (!string.Equals(Value, _lastPushed, StringComparison.Ordinal))
            {
                _currentValue = Value;
                _lastPushed = Value;
                _statusMessage = null;
                _pendingParamReload = true;
            }
        }
        else if (!string.Equals(_lastParamValue, Value, StringComparison.Ordinal))
        {
            // UNCONTROLLED: component owns the live value; adopt the parameter
            // only when the parent genuinely changes it. An unrelated re-render
            // that re-supplies the same (or stale) Value must NOT clobber the
            // drawn signature.
            _currentValue = Value;
            _statusMessage = null;
            _pendingParamReload = true;
        }

        _lastParamValue = Value;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _selfRef = DotNetObjectReference.Create(this);
            _lastStrokeColor = StrokeColor;
            _lastStrokeWidth = StrokeWidth;
            _lastDisabled = Disabled;
            _lastWidth = Width;
            _lastHeight = Height;

            var options = new
            {
                strokeColor = StrokeColor,
                strokeWidth = StrokeWidth,
                mimeType = MimeType,
                debounceMs = 200,
                disabled = Disabled,
                initialDataUrl = _currentValue,
            };

            await Interop.SignaturePadInit(_canvasId, options, _selfRef);
            _initialised = true;
            return;
        }

        if (!_initialised) return;

        // Sync mutable parameters back into the JS pad on parent re-render. We
        // skip the work when nothing changed to avoid resetting the in-flight
        // stroke / wiping the canvas mid-signing.
        if (!string.Equals(_lastStrokeColor, StrokeColor, StringComparison.Ordinal)
            || Math.Abs(_lastStrokeWidth - StrokeWidth) > 0.0001)
        {
            await Interop.SignaturePadSetStrokeStyle(_canvasId, StrokeColor, StrokeWidth);
            _lastStrokeColor = StrokeColor;
            _lastStrokeWidth = StrokeWidth;
        }

        if (_lastDisabled != Disabled)
        {
            await Interop.SignaturePadSetDisabled(_canvasId, Disabled);
            _lastDisabled = Disabled;
        }

        // A runtime Width/Height change re-emits the <canvas> width/height
        // attributes, which resets (blanks) the drawing buffer. Repaint the
        // existing signature after the surface reset so the drawing survives a
        // resize. Skipped when a param reload is already pending — that block
        // repaints from the same value below, so we'd otherwise load twice.
        if ((_lastWidth != Width || _lastHeight != Height) && !_pendingParamReload)
        {
            _lastWidth = Width;
            _lastHeight = Height;
            await Interop.SignaturePadLoadDataUrl(_canvasId, _currentValue);
        }
        else if (_lastWidth != Width || _lastHeight != Height)
        {
            // Param reload will repaint; just sync the tracked dimensions.
            _lastWidth = Width;
            _lastHeight = Height;
        }

        // Programmatic Value updates: repaint the canvas ONLY when the parent
        // actually changed the Value parameter (flagged in OnParametersSet).
        // A value emitted by our own OnStrokeEnded never sets this flag, so a
        // one-way binding or a normalised round-trip can't trigger the
        // destructive loadDataUrl that wiped the just-drawn signature.
        if (_pendingParamReload)
        {
            _pendingParamReload = false;
            await Interop.SignaturePadLoadDataUrl(_canvasId, _currentValue);
        }
    }

    [JSInvokable]
    public async Task OnStrokeEnded(string? dataUrl)
    {
        // Store the drawn value in our backing field — NOT in the Value
        // [Parameter]. Writing Value here would let a subsequent parent
        // re-render (one-way binding, or a controlled parent that hasn't yet
        // echoed the change) reset Value and trip the reload path, wiping the
        // signature. Record it as the value we emitted so a controlled parent
        // echoing the identical string back is recognised as our own
        // round-trip and skips the destructive reload.
        _currentValue = dataUrl;
        _lastPushed = dataUrl; // set BEFORE ValueChanged so a synchronous controlled
        _statusMessage = null; // re-render sees the echo and skips the destructive reload
        await ValueChanged.InvokeAsync(dataUrl);
        await OnSign.InvokeAsync();
        StateHasChanged();
    }

    public async Task ClearAsync()
    {
        await Interop.SignaturePadClear(_canvasId);
        // Clear the live value via the backing field; the canvas is already
        // blank from SignaturePadClear, so no reload is needed. As with
        // OnStrokeEnded, record the emitted value so a controlled parent setting
        // Value=null in response doesn't re-trigger a reload.
        _currentValue = null;
        _lastPushed = null; // set BEFORE ValueChanged (same echo-detection as OnStrokeEnded)
        _statusMessage = L["SignaturePad.Cleared"];
        await ValueChanged.InvokeAsync(null);
        await OnClear.InvokeAsync();
        StateHasChanged();

        // Clearing disables the Clear button (the pad is empty), so a keyboard /
        // switch-access user who activated it loses focus to <body>. Move focus
        // back to the labelled wrapper region so the pad stays operable. This is
        // idempotent for the Escape/Delete path (focus is already inside the
        // region) and the needed restore for the Clear-button path.
        try { await Interop.FocusElement(_wrapperId); }
        catch (JSDisconnectedException) { }
    }

    // Escape / Delete / Backspace clear the pad when it (or a child) has focus,
    // so the canvas is operable without a pointer (#192). No-op while disabled
    // or already empty.
    private async Task HandleKeyDownAsync(KeyboardEventArgs e)
    {
        if (Disabled || string.IsNullOrEmpty(_currentValue)) return;
        if (e.Key is "Escape" or "Delete" or "Backspace")
        {
            await ClearAsync();
        }
    }

    private async Task HandleDownloadAsync()
    {
        // Read the freshest data URL straight from the canvas in case the
        // debounced ValueChanged hasn't fired yet — otherwise a fast user who
        // hits Download right after their last stroke would download the
        // previous version (or null).
        var dataUrl = await Interop.SignaturePadDataUrl(_canvasId, MimeType) ?? _currentValue;
        if (string.IsNullOrEmpty(dataUrl)) return;

        var commaIndex = dataUrl.IndexOf(',', StringComparison.Ordinal);
        if (commaIndex < 0) return;
        var base64 = dataUrl[(commaIndex + 1)..];
        var fileName = $"signature.{(Format?.Equals("svg", StringComparison.OrdinalIgnoreCase) == true ? "svg" : "png")}";
        await Interop.DownloadFile(fileName, base64, MimeType);
    }

    public async ValueTask DisposeAsync()
    {
        try { await Interop.SignaturePadDestroy(_canvasId); } catch (JSDisconnectedException) { }
        _selfRef?.Dispose();
    }
}
